import java.util.*;

public class Solution {
    public static long solve(long[][] grid, long k) {
        int m = grid.length;
        int n = grid[0].length;
        PriorityQueue<long[]> heap = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
        heap.offer(new long[]{0, 0, 0, k});

        long[][][] visited = new long[m][n][(int)k + 1];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                Arrays.fill(visited[i][j], Long.MAX_VALUE);
            }
        }
        visited[0][0][(int)k] = 0;

        int[][] directions = {{0, 1}, {1, 0}};

        while (!heap.isEmpty()) {
            long[] current = heap.poll();
            long cost = current[0];
            int i = (int)current[1];
            int j = (int)current[2];
            int remaining_k = (int)current[3];

            if (i == m - 1 && j == n - 1) {
                return cost;
            }

            if (cost > visited[i][j][remaining_k]) {
                continue;
            }

            for (int[] dir : directions) {
                int ni = i + dir[0];
                int nj = j + dir[1];
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    long newCost = cost + grid[ni][nj];
                    if (newCost < visited[ni][nj][remaining_k]) {
                        visited[ni][nj][remaining_k] = newCost;
                        heap.offer(new long[]{newCost, ni, nj, remaining_k});
                    }
                }
            }

            if (remaining_k > 0) {
                for (int x = 0; x < m; x++) {
                    for (int y = 0; y < n; y++) {
                        if (grid[x][y] <= grid[i][j] && (x != i || y != j)) {
                            if (cost < visited[x][y][remaining_k - 1]) {
                                visited[x][y][remaining_k - 1] = cost;
                                heap.offer(new long[]{cost, x, y, remaining_k - 1});
                            }
                        }
                    }
                }
            }
        }

        return -1;
    }
}
